 {"id":"bd-nzv3.11","title":"btrfs multi-device RAID: supported profile matrix and architectural design","description":"Define the first supported multi-device btrfs surface in enough detail to implement it safely: profile matrix, superblock/device discovery flow, chunk and stripe mapping model, degraded-mode policy, and interactions with block/core/repair layers.","acceptance_criteria":"Closure requires: explicit supported profiles, explicit unsupported profiles, device-failure assumptions, touch points across crates, operator-visible device assembly/degraded-mode workflow, and spec/parity text that makes the initial support boundary measurable instead of aspirational.","notes":"Also define the verification matrix: healthy mount, missing-device mount behavior, degraded-mode remount/read behavior, read-path mapping, write-path constraints if any, and the exact log/CLI fields needed to explain device/chunk decisions and remediation steps.","status":"open","priority":1,"issue_type":"task","created_at":"2026-03-23T01:06:22.365316340Z","created_by":"ubuntu","updated_at":"2026-03-23T06:15:44.442133874Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["btrfs","multidevice","raid","spec"],"dependencies":[{"issue_id":"bd-nzv3.11","depends_on_id":"bd-nzv3","type":"parent-child","created_at":"2026-03-23T01:06:22.365316340Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-nzv3.12","title":"btrfs multi-device RAID: implement device discovery and chunk mapping core","description":"Implement the foundational multi-device support selected in bd-nzv3.11: device set discovery, chunk-tree interpretation, logical-to-physical mapping, and the minimum mount/read/write plumbing needed for the chosen profile set.","acceptance_criteria":"Closure requires: deterministic core mapping tests, integration tests spanning at least healthy and degraded configurations within the supported matrix, and explicit diagnostics for unsupported or unsafe profile/device states.","notes":"Keep unsupported profiles loud. The system should refuse or degrade explicitly rather than guessing.","status":"open","priority":1,"issue_type":"feature","created_at":"2026-03-23T01:06:23.428684215Z","created_by":"ubuntu","updated_at":"2026-03-23T06:16:03.950439160Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["btrfs","implementation","multidevice","qa_e2e_required","qa_structured_logging_required","qa_unit_required","raid"],"dependencies":[{"issue_id":"bd-nzv3.12","depends_on_id":"bd-nzv3","type":"parent-child","created_at":"2026-03-23T01:06:23.428684215Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-nzv3.12","depends_on_id":"bd-nzv3.11","type":"blocks","created_at":"2026-03-23T06:11:27.885763973Z","created_by":"PearlFox","metadata":"{}","thread_id":""},{"issue_id":"bd-nzv3.12","depends_on_id":"bd-nzv3.24","type":"blocks","created_at":"2026-03-23T06:16:03.949651790Z","created_by":"PearlFox","metadata":"{}","thread_id":""}]}
