 {"id":"bd-nzv3.13","title":"btrfs multi-device RAID: redundancy tests, repair interplay, and e2e diagnostics","description":"Turn the multi-device core into a user-trustworthy feature by adding deterministic redundancy tests, repair/scrub interaction coverage, and end-to-end scripts with detailed logs for healthy, degraded, and rejected-profile scenarios.","acceptance_criteria":"Closure requires: fixture-backed multi-device scenarios, repair/scrub assertions where relevant, at least one e2e script with rich logging, and docs/parity updates that state exactly which RAID/device modes are covered.","notes":"This bead owns the user-facing proof that multi-device support is real and diagnosable.","status":"open","priority":2,"issue_type":"task","created_at":"2026-03-23T01:06:24.487009536Z","created_by":"ubuntu","updated_at":"2026-03-23T06:16:05.174162833Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["btrfs","multidevice","qa_e2e_required","qa_structured_logging_required","qa_unit_required","raid","tests"],"dependencies":[{"issue_id":"bd-nzv3.13","depends_on_id":"bd-nzv3","type":"parent-child","created_at":"2026-03-23T01:06:24.487009536Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-nzv3.13","depends_on_id":"bd-nzv3.12","type":"blocks","created_at":"2026-03-23T06:11:29.007893166Z","created_by":"PearlFox","metadata":"{}","thread_id":""},{"issue_id":"bd-nzv3.13","depends_on_id":"bd-nzv3.24","type":"blocks","created_at":"2026-03-23T06:16:05.173340587Z","created_by":"PearlFox","metadata":"{}","thread_id":""}]}
+{"id":"bd-nzv3.13.1","title":"btrfs RAID validation: redundancy and degraded-mode regression tests","description":"Add deterministic tests for healthy redundancy behavior, degraded reads, and explicit unsupported-profile rejection behavior.","status":"open","priority":2,"issue_type":"task","created_at":"2026-03-23T06:18:48.706838468Z","created_by":"PearlFox","updated_at":"2026-03-23T06:20:20.547748283Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["btrfs","multidevice","raid","tests"],"dependencies":[{"issue_id":"bd-nzv3.13.1","depends_on_id":"bd-nzv3.12.3","type":"blocks","created_at":"2026-03-23T06:20:20.546772757Z","created_by":"PearlFox","metadata":"{}","thread_id":""},{"issue_id":"bd-nzv3.13.1","depends_on_id":"bd-nzv3.13","type":"parent-child","created_at":"2026-03-23T06:18:48.706838468Z","created_by":"PearlFox","metadata":"{}","thread_id":""}]}
